const s = $input.first().json;
const emoji = (s.direcao || '').toUpperCase() === 'COMPRA' ? '🟢' : '🔴';
const dir = (s.direcao || '').toUpperCase() === 'COMPRA' ? 'COMPRA ▲' : 'VENDA ▼';
return [{
  json: {
    mensagem: `${emoji} *SINAL ${dir}*\n\n*Ativo:* ${s.ativo || '-'}\n*Preço:* R$ ${Number(s.preco || 0).toFixed(2)}\n*Motivo:* ${s.motivo || '-'}\n*Hora:* ${s.timestamp || new Date().toLocaleTimeString('pt-BR')}\n\n_Trader-good • automático_`
  }
}];
